column6:
"IF (GETTOKEN.HTTP_CODE==200) && ISEQUAL(GETTOKEN.VALUE.token_type,'Bearer') THEN
    X.192 := 'Token received';
    X.201 := 1;
    $.GPARAM.TOKENTYPE := GETTOKEN.VALUE.token_type;
    $.GPARAM.EXPIRESIN := GETTOKEN.VALUE.expires_in;
    $.GPARAM.ACCESSTOKEN := GETTOKEN.VALUE.access_token;
    $.GPARAM.EXPIRESDATE := ( ( $.GPARAM.EXPIRESIN * 5 ) / 6 ) + $.SYS.TIME;
ELSE
    $.GPARAM.EXPIRESDATE := 60 + $.SYS.TIME;
    X.192 := GETTOKEN.VALUE.error;
    X.201 := 0;
ENDIF;
IF ( LEN(X.192) == 0 ) THEN
    X.192 := 'Token Error';
ENDIF;
IF ISEQUAL($.GPARAM.VERBOSE,'ON') THEN
    DEBUG(GETTOKEN.URL);
    DEBUG(GETTOKEN.HTTP_CODE);
    DEBUG(GETTOKEN.HTTP_DATA);
ENDIF;
MSG_INFO_TIME := $.SYS.TIME;
GETTOKEN.F := 0;"

"IF GETSLAVESROOMS.HTTP_CODE == 200  THEN
    X.192 := 'Slaves received';
    $.GPARAM.SLAVELIST:=GETSLAVESROOMS.ASLIST.value[].emailAddress;
    X.200 := 1;
ELSE
    X.192 := GETSLAVESROOMS.VALUE.error.code;
    X.200 := 0;
ENDIF;
IF ( LEN(X.192) == 0 ) THEN
    X.192 := 'Slaves Error';
ENDIF;
IF ISEQUAL($.GPARAM.VERBOSE,'ON') THEN
    DEBUG(GETSLAVESROOMS.URL);
    DEBUG(GETSLAVESROOMS.HTTP_CODE);
    DEBUG(GETSLAVESROOMS.HTTP_DATA);
ENDIF;
MSG_INFO_TIME := $.SYS.TIME;
GETSLAVESROOMS.F := 0;"

"IF GETCURRENTVIEW.HTTP_CODE == 200  THEN
    X.190 := 'Current received';
    X.200 := 1;
    COUNT := GETCURRENTVIEW.ARRAY.LEN.value;
ELSE
    X.190 := GETCURRENTVIEW.VALUE.error.code;
    X.200 := 0;
ENDIF;
IF ( LEN(X.190) == 0 ) THEN
    X.190 := 'Current Error';
ENDIF;
IF ( GETCURRENTVIEW.HTTP_CODE == 200 ) && COUNT THEN
    X.50 := 1;  X.60 := 0;
ELSE
    X.50 := 0;  X.60 := 1;
ENDIF;
IF ISEQUAL($.GPARAM.VERBOSE,'ON') THEN
    DEBUG(GETCURRENTVIEW.URL);
    DEBUG(GETCURRENTVIEW.HTTP_CODE);
    DEBUG(GETCURRENTVIEW.HTTP_DATA);
ENDIF;
EVENTREFRESHDATE := DEC($.SYS.TIME, 300) * 300 + 310;
EVENTREFRESHDATE_STR := DATE(EVENTREFRESHDATE);
X.181 := SUBSTRING(EVENTREFRESHDATE_STR,11,8);
MSG_TIME := $.SYS.TIME;
GETCURRENTVIEW.F := 0;"

"IF GETFUTUREVIEW.HTTP_CODE == 200 THEN
    X.190 := 'Upcoming received';
    X.200 := 1;
    X.0 := GETFUTUREVIEW.ARRAY.LEN.value;
    X.1 := GETFUTUREVIEW.VALUE.value[0].subject;
    X.2 := GETFUTUREVIEW.VALUE.value[0].start.dateTime;
    X.3 := GETFUTUREVIEW.VALUE.value[0].end.dateTime;
    X.4 := GETFUTUREVIEW.VALUE.value[0].end.timeZone;
ELSE
    X.190 := GETFUTUREVIEW.VALUE.error.code;
    X.200 := 0;
ENDIF;
IF ( LEN(X.190) == 0 ) THEN
    X.190 := 'Future Error';
ENDIF;
IF ( GETFUTUREVIEW.HTTP_CODE == 200 ) && X.0 THEN
    X.51 := 1;  X.61 := 0;
    DAY_TMP  := SUBSTRING(X.2,8,2);
    MONTH_TMP := SUBSTRING(X.2,5,2);
    YEAR_TMP := SUBSTRING(X.2,0,4);
    TIME_TMP := SUBSTRING(X.2,11,8);
    X.22 := CONCAT(DAY_TMP,'.',MONTH_TMP,'.',YEAR_TMP,' - ', TIME_TMP);
    DAY_TMP  := SUBSTRING(X.3,8,2);
    MONTH_TMP := SUBSTRING(X.3,5,2);
    YEAR_TMP := SUBSTRING(X.3,0,4);
    TIME_TMP := SUBSTRING(X.3,11,8);
    X.23 := CONCAT(DAY_TMP,'.',MONTH_TMP,'.',YEAR_TMP,' - ', TIME_TMP);
ELSE
    X.22 := '';
    X.23 := '';
    X.51 := 0;  X.61 := 1;
ENDIF;
IF ISEQUAL($.GPARAM.VERBOSE,'ON') THEN
    DEBUG(GETFUTUREVIEW.URL);
    DEBUG(GETFUTUREVIEW.HTTP_CODE);
    DEBUG(GETFUTUREVIEW.HTTP_DATA);
ENDIF;
MSG_TIME := $.SYS.TIME;
GETFUTUREVIEW.F := 0;"

column10:
"IF ( MSG_TIME + 3 - $.SYS.TIME ) <= 0 THEN
    X.190 := '';
ENDIF;"
IF ( MSG_INFO_TIME + 10 - $.SYS.TIME ) <= 0 THEN
    X.192 := '';
ENDIF;"

"IF FORCE_FUTURE_NEXT THEN
    GETFUTUREVIEW.F := 1;
    FORCE_FUTURE_NEXT := 0;
ENDIF;
X.170 := EVENTREFRESHDATE - $.SYS.TIME;
IF X.170 <= 0 THEN X.170 :=0; ENDIF;
IF X.195 && ( LEN($.GPARAM.ACCESSTOKEN) > 0 ) && (X.170 == 0) THEN
    TIME_NOW := $.SYS.TIME;
    TIME_FUTURE := TIME_NOW + ( X.52 * 60 * 60 );
    GETCURRENTVIEW.F := 1;
    FORCE_FUTURE_NEXT := 1;
    DEBUG_INFO := 'Event Request'; DEBUG(DEBUG_INFO);
ENDIF;"

"X.180 := $.GPARAM.EXPIRESDATE - $.SYS.TIME;
IF X.180 <= 0 THEN X.180 :=0; ENDIF;
IF ISEQUAL($.PARAM.SLAVE,$.GPARAM.SLAVE) && X.195 && (X.180 == 0) THEN 
    GETTOKEN.F :=1;
    DEBUG_INFO := 'Token Request'; DEBUG(DEBUG_INFO);
ENDIF;"

"IF X.50 THEN TR_MSG_NOW := 'On'; ELSE TR_MSG_NOW := 'Off'; ENDIF;
IF X.51 THEN TR_MSG_UP := 'On'; ELSE TR_MSG_UP := 'Off'; ENDIF;
STRNB := DECIMAL_TO_STRING(X.52);
X.191 := CONCAT(TR_MSG_NOW,' | ',TR_MSG_UP,' ',STRNB,' h');"
